#include <stdio.h>
#include <stdlib.h>

#define RING_SIZE 4

typedef struct {
    int items[RING_SIZE];
    int count;
} RingBuf;

int main(void) {
    RingBuf *shm = (RingBuf *)calloc(1, sizeof(RingBuf));

    // Producteur
    for (int i = 0; i < 2; i++) {
        shm->items[shm->count] = i + 1;
        printf("Producer wrote: item=%d seq=%d\n", i + 1, shm->count);
        shm->count++;
    }

    // Consommateur
    for (int i = 0; i < 2; i++) {
        printf("Consumer read: item=%d\n", shm->items[i]);
    }

    free(shm);
    return 0;
}

