#include <stdlib.h>

#define RING_SIZE 4
typedef struct { int items[RING_SIZE]; int count; } RingBuf;

/* == EXEMPLE ===============================================
 * Circular log buffer sur memoire partagee simulee
 * Ecrit des entries dans un ring buffer, lit ensuite.
 * ========================================================= */
typedef struct { char entries[RING_SIZE][16]; int idx; } LogBuf;

void example_circular_log(void) {
    LogBuf *log = (LogBuf *)calloc(1, sizeof(LogBuf));
    const char *msgs[] = {"boot", "ready"};
    for (int i = 0; i < 2; i++) {
        snprintf(log->entries[log->idx], 16, "%s", msgs[i]);
        printf("Log wrote: entry=%s seq=%d\n", msgs[i], log->idx);
        log->idx++;
    }
    for (int i = 0; i < 2; i++) {
        printf("Log read: entry=%s\n", log->entries[i]);
    }
    free(log);
}
/* Resultat: Log wrote boot seq=0, Log wrote ready seq=1, Log read boot, Log read ready */

